var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"으야아아앗!","JPN":"うぎゃあああっ！","ENG":"Gaaahhhh!","TWN":"呃啊啊啊！"},"stage":{"bg":"CAR","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L5_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"으으, 침식체 놈들이 얼마나 헤집고 다닌 거죠? 도대체가 멀쩡한 도로가 없잖아요!","JPN":"うう、侵食体の奴ら、どれだけ暴れたの？　まともな道路がないわ！","ENG":"Ngh, how much have those C.O.s been destroying? All the roads are a mess!","TWN":"唉，那些侵蝕體把幾乎所有的道路都破壞掉了！"},"stage":{"bg":"CAR","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L6_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"교통 통제 상황에 따르면 그 방향이 가장 안전한 최단루트야.","JPN":"交通統制状況によると、この方向が一番安全な最短ルートだよ。","ENG":"According to traffic control, this is the safest and shortest route.","TWN":"根據交通管制情況，那個方向是最安全、最短的路線。"},"stage":{"bg":"CAR","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_HATE"}}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L7_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"원래는 차원함선이 가장 빠른 수단이겠지만… 하늘에 깔린 침식체들의 공세를 견딜 만큼 튼튼한 함선은 지금 샤레이드에 없으니까.","JPN":"元々は次元艦船が一番早いけど……空いっぱいの侵食体たちの攻勢に耐えられるほど頑丈な艦船は今シャレードにないからね。","ENG":"A dimensional ship would be the fastest option, but... there are no dimensional ships in Charade that can withstand the attacks from all those C.O.s filling up the sky.","TWN":"本來乘坐次元艦船是最快的方法……但是目前查雷德沒有足夠堅固的艦船來抵禦空中的侵蝕體攻擊。"},"stage":{"bg":"CAR","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L10_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"그런데 괜찮을까요? 방금 지나온 거리에도 침식체들이 저렇게 많은데 저희끼리 가버려도…","JPN":"でも、大丈夫でしょうか？　今通ってきた道にも侵食体があんなに沢山いるのに、私たちだけで行っちゃっても……","ENG":"Will it be okay, though? I just saw so many C.O.s on the street we just passed. If we ignore it...","TWN":"但這樣走掉真的可以嗎？我們在路上遇到了那麼多侵蝕體，如果連我們也離開……"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"걱정 마. 내 직감에 의하면 우리가 가는 곳이 훨씬 더 위험할 걸?","JPN":"心配するな。私の直感によると、これから私たちが行くところはもっと危ないはずだから。","ENG":"Don't worry. My gut tells me that where we're headed is much more dangerous.","TWN":"別擔心。我的直覺告訴我，我們要去的地方比這裡更危險。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"그리고, 사장님이 믿을만한 사람들에게 뒤를 맡겼다고 했으니 괜찮을 거야.","JPN":"それに、社長が信頼できる人たちに後ろを任せたって言ってたから、大丈夫だよ。","ENG":"And Boss said he left the city in good hands. So it should be fine.","TWN":"而且老闆說他會交給可以信任的人，所以不會有事的。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_LAUGH"}}}},{"id":"L13_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"그럴까요…?","JPN":"そうでしょうか……？","ENG":"Really...?","TWN":"是這樣嗎……？"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_LAUGH"}}}},{"id":"L15_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"물론. 다들 무사할 걸세.","JPN":"もちろんさ。みんな無事に決まってる。","ENG":"Of course. Everyone will be safe.","TWN":"當然，大家都沒事的。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_LAUGH"}}}},{"id":"L16_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"정 남아있는 사람들이 걱정된다면, 현장의 우리 특수요원과 통화라도 해보겠나?","JPN":"残っている人たちが心配なら、現場の特殊エージェントと通話してみるか？","ENG":"If you're that worried, would you like to call our special agents out on the field?","TWN":"如果你擔心其他人，可以聯絡一下現場的特務。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_LAUGH"}}}},{"id":"L17_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"우와아, 특수요원이요?!","JPN":"うわあ、特殊エージェントですか！？","ENG":"Whoa, special agents?!","TWN":"哇，特務？"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_LAUGH"}}}},{"id":"L19_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"여기는 블랙 버드. 샤레이드 방어 작전은 순조롭게 진행되고 있다. 무슨 일이지?","JPN":"こちら、ブラックバード。ブラックバード防御作戦は順調だ。どうした？","ENG":"This is Blackbird. The defense operation in Charade is going smooth. What's up?","TWN":"我是黑鳥。查雷德防禦戰進展順利，有什麼事嗎？"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"확인 차 연락했네. 우리 직원이 자네들의 안위를 걱정해서 말이야.","JPN":"確認がてら連絡した。私の職員が君たちの安否を心配していてね。","ENG":"Just checking up. My employee was worried about your safety.","TWN":"只是確認一下情況，我的員工很擔心你們的安全。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"붙들어 매라고. 코핀 컴퍼니. 블랙 버드의 파견대는 실패라는 걸 용납하지 않으니까.","JPN":"心配するな、コフィンカンパニー。ブラックバードの派遣隊は失敗を許さない。","ENG":"Leave it to us, Coffin Company. Blackbird's forces don't tolerate failure.","TWN":"不用擔心，科芬公司，因為黑鳥特遣隊絕不容忍失敗。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"오오오, 짱 멋진 코드네임! 멋진 선글라스랑 멋진 콧수염까지! 엄청 믿음직해 보여요!","JPN":"うわあ、カッコいいコードネーム！　素敵なサングラスに、立派な口ひげまで！　ものすごく頼もしいです！","ENG":"Ooooh, a super cool codename! Cool sunglasses and a cool mustache! He seems so reliable!","TWN":"哇喔喔喔！好帥的代號！還有墨鏡和鬍鬚！看起來超可靠的！"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L26_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"훗, 펜릴 소대의 신참인가? 뭘 좀 아는 친구로군.","JPN":"ふっ、フェンリル小隊の新入りか？　わかっているな。","ENG":"Heh. A newbie in Fenrir Squad? You're pretty sharp.","TWN":"哈哈，芬里爾小隊的新人？你蠻有眼光的。"},"stage":{"bg":"COUNTERSIDE_ANCIENT","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"이쪽은 최고의 요원들이 맡고 있으니 걱정은 붙들어 매라고.","JPN":"こちらは最高のエージェントたちが担当している、心配無用さ。","ENG":"The best agents are on the job here, so don't you worry.","TWN":"在這裡的都是最強的，放一百個心吧。"},"stage":{"bg":"CITY_STREET_NORMAL_02","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SPEAR_PERSONA_NULL_NULL","text":{"KOREA":"현장지휘하러 나왔으면서 멋부리는 수준은 혼자 일류 카운터네요.","JPN":"現場の指揮で来てるくせに、オシャレだけは一流カウンターだわ。","ENG":"First-class Counter behavior to look all cool when you're actually out here to command people.","TWN":"明明是來現場指揮的還這樣耍帥，只有你是一流制裁者嗎。"},"stage":{"bg":"CITY_STREET_NORMAL_02","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAR_PERSONA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"음? 리코리스 양은 평소 보던 것과 분위기가 다른데.","JPN":"うむ？　リコリス君は、普段とは雰囲気が違うな。","ENG":"Hmm? Lycoris, you look different from usual.","TWN":"嗯？莉克莉絲今天和往常不太一樣喔。"},"stage":{"bg":"CITY_STREET_NORMAL_02","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAR_PERSONA_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L33_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"이번엔 메이드 복장으로 출전하지 않는 건가?","JPN":"今回はメイド服で出戦しないのか？","ENG":"Are you not fighting in your maid costume?","TWN":"你這次怎麼沒穿女僕裝？"},"stage":{"bg":"CITY_STREET_NORMAL_02","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAR_PERSONA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"SPEAR_PERSONA_NULL_NULL","text":{"KOREA":"나 참, 누가 싸우러 나와서 그런 걸 입고 다녀요?","JPN":"まったく、誰が戦うときにそんな服着を着るの？","ENG":"Come on, who would join a fight in that kind of outfit?","TWN":"我說，誰會穿那樣的衣服出去任務？"},"stage":{"bg":"CITY_STREET_NORMAL_02","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_PERSONA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"리코리스, 옷 하나 갈아입었다고 벌써 자신의 정체성을 망각해버린 건가요?","JPN":"リコリス、着替えたからといって、もう自分のアイデンティティを忘れてしまったのですか？","ENG":"Lycoris, you can't forget who you truly are just because you're in a different costume!","TWN":"莉克莉絲，只是換了一身衣服就忘了自己是誰嗎？"},"stage":{"bg":"CITY_STREET_NORMAL_02","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_PERSONA_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"맞슴다! 리코리스가 이런 식으로 메이드의 정체성을 배반할 줄은 몰랐슴다!","JPN":"そうっす！　リコリスがこんな風にメイドのアイデンティティを裏切るとは思ってもいなかったっす！","ENG":"That's right! I didn't know you'd betray your maid identity, Lycoris!","TWN":"沒錯！沒想到莉克莉絲會這樣背叛女僕的身分！"},"stage":{"bg":"CITY_STREET_NORMAL_02","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"SPEAR_PERSONA_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"SPEAR_PERSONA_NULL_NULL","text":{"KOREA":"난 처음부터 이게 정체성이었거든?!","JPN":"私は最初からこれがアイデンティティなんだけど！？","ENG":"This was always my true identity, okay?!","TWN":"我的身分從一開始就是這個好不好？！"},"stage":{"bg":"CITY_STREET_NORMAL_02","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_PERSONA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"걱정 말게. 전에도 말했지만, 자네가 편한대로 입더라도 그걸 지적할 대원은 없을 거야.","JPN":"心配するな。前にも話したが、君が好きな服を着てもそれを指摘する隊員はいないだろう。","ENG":"Don't worry. Like I mentioned before, no one's going to judge you for wearing what you feel comfortable in.","TWN":"別擔心。正如我之前說過，你想穿什麼就穿什麼，沒人會指責。"},"stage":{"bg":"CITY_STREET_NORMAL_02","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SPEAR_PERSONA_NULL_NULL","text":{"KOREA":"전혀 안 편해! 안 입을 거라고!","JPN":"全然好きじゃないし、着ないってば！","ENG":"It's not comfortable at all! I'm not going to wear it!","TWN":"一點都不舒服！我才不會穿！"},"stage":{"bg":"CITY_STREET_NORMAL_02","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_PERSONA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그럼 다들 조금 더 고생해주게. 샤레이드 시민들의 안위를 부탁하지.","JPN":"それでは、みんなもう少しだけ頑張ってくれ。シャレードの市民の安全を頼む。","ENG":"Well then, keep up the good work. I'll leave the safety of Charade's citizens to you.","TWN":"那就請你們加油吧。保護查雷德市民的安全。"},"stage":{"bg":"CITY_STREET_NORMAL_02","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_PERSONA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"이번 사태의 원인을 파악하러 간다던데, 신참 아가씨가 부디 잘 서포트해줘.","JPN":"この事態の原因を把握しに行くと聞いたが、新入りのお嬢さんがちゃんとサポートしてやってくれ。","ENG":"I heard you were going to investigate what's behind all this. Make sure to back them up, newbie!","TWN":"聽說要去查明本次事件的真相，請新人好好協助。"},"stage":{"bg":"CITY_STREET_NORMAL_02","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"네! 이쪽은 저희에게 맡겨주세요, 요원님!","JPN":"はい！　こちらは私たちに任せてください、エージェントさん！","ENG":"Yup! Leave it to us, Mr. Agent!","TWN":"是！交給我們吧！"},"stage":{"bg":"CITY_STREET_NORMAL_02","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"어떤가? 노엘 양. 이제 좀 안심이 되나?","JPN":"どうだ？　ノエル君。これで安心できたかね？","ENG":"What do you think, Noelle? Are you relieved?","TWN":"怎麼樣？洛艾兒，這下可以放心了吧？"},"stage":{"bg":"CAR","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"네! 저렇게나 여유로운 모습! 뭘 입고 있어도 프로는 프로네요!","JPN":"はい！　あの余裕溢れる姿！　どんな服を着ていてもプロはプロですね！","ENG":"Yes! That relaxed exterior! A pro is a pro, no matter what she's wearing!","TWN":"嗯！看看那從容不迫的姿態！專家果然不論穿什麼都是專家！"},"stage":{"bg":"CAR","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"사장님! 저희도 나중에 저런 옷 입어봐도 되나요?","JPN":"社長！　私たちも今度、あんな服を着てみてもいいですか？","ENG":"Boss! Can we wear stuff like that in the future?","TWN":"老闆！我們以後也能試試那樣的衣服嗎？"},"stage":{"bg":"CAR","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"물론이지. 이번 일이 끝나면 홍보부서에 펜릴 소대를 위한 특별의상을 부탁해 두겠네.","JPN":"もちろんさ。この仕事が終われば、広報チームにフェンリル小隊のための特別衣装を頼んでおくとしよう。","ENG":"Of course. After we're done with this, I'll ask the marketing department to prepare a special costume for Fenrir Squad.","TWN":"當然。事情結束後，我會讓宣傳部為芬里爾小隊準備一套特別的制服。"},"stage":{"bg":"CAR","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"저기… 두 사람. 지금 정장 얘기하는 거 맞지?","JPN":"あの……二人とも。今スーツの話をしてるんだよね？","ENG":"Uh... You two are talking about suits, right?","TWN":"那個……你們二位說的是西裝，對吧？"},"stage":{"bg":"CAR","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SURPRISE"},"R":null}}}]`);export{e as default};